$controllers = [
    // ----------------- DASHBOARD -----------------
    'app/Http/Controllers/Penjual/DashboardController.php' => "<?php\n\nnamespace App\Http\Controllers\Penjual;\n\nuse App\Http\Controllers\Controller;\nuse Illuminate\Http\Request;\nuse App\Models\{Store, Product, Order};\nuse Illuminate\Support\Facades\Auth;\n\nclass DashboardController extends Controller\n{\n    public function index(Request \$request)\n    {\n        \$store = Auth::user()->stores()->first();\n        if (!\$store) {\n            if (\$request->wantsJson()) return response()->json(['message' => 'Anda belum memiliki toko'], 404);\n            return redirect()->route('penjual.store.index')->with('warning', 'Silakan lengkapi data toko Anda terlebih dahulu');\n        }\n\n        \$data = [\n            'store' => \$store,\n            'total_products' => Product::where('id_toko', \$store->id_toko)->count(),\n            'total_orders' => Order::where('id_toko', \$store->id_toko)->count(),\n            'pending_orders' => Order::where('id_toko', \$store->id_toko)->where('status_pesanan', 'menunggu')->count(),\n        ];\n\n        if (\$request->wantsJson()) return response()->json(\$data);\n        return view('penjual.dashboard', compact('data'));\n    }\n}\n",

    // ----------------- PRODUCT -----------------
    'app/Http/Controllers/Penjual/ProductController.php' => "<?php\n\nnamespace App\Http\Controllers\Penjual;\n\nuse App\Http\Controllers\Controller;\nuse Illuminate\Http\Request;\nuse App\Models\Product;\nuse Illuminate\Support\Facades\Auth;\nuse Illuminate\Support\Facades\Storage;\n\nclass ProductController extends Controller\n{\n    private function getStore() {\n        return Auth::user()->stores()->first();\n    }\n\n    public function index(Request \$request)\n    {\n        \$store = \$this->getStore();\n        if (!\$store) return response()->json(['message' => 'Toko tidak ditemukan'], 404);\n\n        \$products = Product::where('id_toko', \$store->id_toko)->with('category')->get();\n        if (\$request->wantsJson()) return response()->json(\$products);\n        return view('penjual.products.index', compact('products'));\n    }\n\n    public function store(Request \$request)\n    {\n        \$store = \$this->getStore();\n        if (!\$store) return response()->json(['message' => 'Toko tidak ditemukan'], 404);\n\n        \$request->validate([\n            'id_kategori' => 'required|exists:categories,id_kategori',\n            'nama_produk' => 'required|string',\n            'deskripsi_produk' => 'nullable|string',\n            'resep' => 'nullable|string',\n            'harga' => 'required|numeric',\n            'stok' => 'required|integer',\n            'foto_produk' => 'nullable|image|max:2048'\n        ]);\n\n        \$data = \$request->all();\n        \$data['id_toko'] = \$store->id_toko;\n\n        if (\$request->hasFile('foto_produk')) {\n            \$data['foto_produk'] = \$request->file('foto_produk')->store('products', 'public');\n        }\n\n        \$product = Product::create(\$data);\n        if (\$request->wantsJson()) return response()->json(['message' => 'Produk ditambahkan', 'product' => \$product], 201);\n        return redirect()->route('penjual.products.index')->with('success', 'Produk berhasil ditambahkan');\n    }\n\n    public function update(Request \$request, \$id)\n    {\n        \$product = Product::where('id_toko', \$this->getStore()->id_toko)->findOrFail(\$id);\n\n        \$request->validate([\n            'id_kategori' => 'required|exists:categories,id_kategori',\n            'nama_produk' => 'required|string',\n            'deskripsi_produk' => 'nullable|string',\n            'resep' => 'nullable|string',\n            'harga' => 'required|numeric',\n            'stok' => 'required|integer',\n            'foto_produk' => 'nullable|image|max:2048'\n        ]);\n\n        \$data = \$request->all();\n        if (\$request->hasFile('foto_produk')) {\n            if (\$product->foto_produk) Storage::disk('public')->delete(\$product->foto_produk);\n            \$data['foto_produk'] = \$request->file('foto_produk')->store('products', 'public');\n        }\n\n        \$product->update(\$data);\n        if (\$request->wantsJson()) return response()->json(['message' => 'Produk diperbarui', 'product' => \$product]);\n        return redirect()->route('penjual.products.index')->with('success', 'Produk berhasil diperbarui');\n    }\n\n    public function destroy(Request \$request, \$id)\n    {\n        \$product = Product::where('id_toko', \$this->getStore()->id_toko)->findOrFail(\$id);\n        if (\$product->foto_produk) Storage::disk('public')->delete(\$product->foto_produk);\n        \$product->delete();\n\n        if (\$request->wantsJson()) return response()->json(['message' => 'Produk dihapus']);\n        return redirect()->route('penjual.products.index')->with('success', 'Produk dihapus');\n    }\n}\n",

    // ----------------- ORDER -----------------
    'app/Http/Controllers/Penjual/OrderController.php' => "<?php\n\nnamespace App\Http\Controllers\Penjual;\n\nuse App\Http\Controllers\Controller;\nuse Illuminate\Http\Request;\nuse App\Models\Order;\nuse Illuminate\Support\Facades\Auth;\n\nclass OrderController extends Controller\n{\n    private function getStore() {\n        return Auth::user()->stores()->first();\n    }\n\n    public function index(Request \$request)\n    {\n        \$orders = Order::where('id_toko', \$this->getStore()->id_toko)->with(['user', 'orderDetails.product'])->get();\n        if (\$request->wantsJson()) return response()->json(\$orders);\n        return view('penjual.orders.index', compact('orders'));\n    }\n\n    public function show(Request \$request, \$id)\n    {\n        \$order = Order::where('id_toko', \$this->getStore()->id_toko)->with(['user', 'orderDetails.product', 'payment'])->findOrFail(\$id);\n        if (\$request->wantsJson()) return response()->json(\$order);\n        return view('penjual.orders.show', compact('order'));\n    }\n\n    public function updateStatus(Request \$request, \$id)\n    {\n        \$order = Order::where('id_toko', \$this->getStore()->id_toko)->findOrFail(\$id);\n        \$request->validate(['status_pesanan' => 'required|in:menunggu,diproses,dikirim,selesai,dibatalkan']);\n        \$order->update(['status_pesanan' => \$request->status_pesanan]);\n\n        if (\$request->wantsJson()) return response()->json(['message' => 'Status pesanan diperbarui', 'order' => \$order]);\n        return redirect()->back()->with('success', 'Status pesanan diperbarui');\n    }\n\n    public function printReceipt(Request \$request, \$id)\n    {\n        \$order = Order::where('id_toko', \$this->getStore()->id_toko)->with(['user', 'orderDetails.product', 'payment'])->findOrFail(\$id);\n        // Usually returns a view styled for printing or PDF\n        return view('penjual.orders.receipt', compact('order'));\n    }\n}\n",

    // ----------------- STORE -----------------
    'app/Http/Controllers/Penjual/StoreController.php' => "<?php\n\nnamespace App\Http\Controllers\Penjual;\n\nuse App\Http\Controllers\Controller;\nuse Illuminate\Http\Request;\nuse App\Models\Store;\nuse Illuminate\Support\Facades\Auth;\n\nclass StoreController extends Controller\n{\n    public function index(Request \$request)\n    {\n        \$store = Auth::user()->stores()->first();\n        if (\$request->wantsJson()) return response()->json(\$store);\n        return view('penjual.store.index', compact('store'));\n    }\n\n    public function update(Request \$request)\n    {\n        \$store = Auth::user()->stores()->first();\n        \$request->validate([\n            'nama_toko' => 'required|string',\n            'alamat_toko' => 'required|string',\n            'jam_buka' => 'nullable|string',\n            'jam_tutup' => 'nullable|string',\n            'deskripsi_toko' => 'nullable|string'\n        ]);\n\n        if (\$store) {\n            \$store->update(\$request->all());\n        } else {\n            \$data = \$request->all();\n            \$data['id_user'] = Auth::id();\n            \$data['status_verifikasi'] = 'menunggu konfirmasi';\n            \$store = Store::create(\$data);\n        }\n\n        if (\$request->wantsJson()) return response()->json(['message' => 'Profil toko diperbarui', 'store' => \$store]);\n        return redirect()->route('penjual.store.index')->with('success', 'Profil diperbarui');\n    }\n}\n",

    // ----------------- REPORT -----------------
    'app/Http/Controllers/Penjual/ReportController.php' => "<?php\n\nnamespace App\Http\Controllers\Penjual;\n\nuse App\Http\Controllers\Controller;\nuse Illuminate\Http\Request;\nuse App\Models\Order;\nuse Illuminate\Support\Facades\Auth;\nuse Illuminate\Support\Facades\DB;\n\nclass ReportController extends Controller\n{\n    public function index(Request \$request)\n    {\n        \$store = Auth::user()->stores()->first();\n        if (!\$store) return response()->json(['message' => 'Toko tidak ditemukan'], 404);\n\n        // Get total sales completed\n        \$total_sales = Order::where('id_toko', \$store->id_toko)\n                            ->where('status_pesanan', 'selesai')\n                            ->sum('total_harga');\n\n        \$data = [\n            'total_sales' => \$total_sales,\n            'orders_completed' => Order::where('id_toko', \$store->id_toko)->where('status_pesanan', 'selesai')->count(),\n        ];\n\n        if (\$request->wantsJson()) return response()->json(\$data);\n        return view('penjual.reports.index', compact('data'));\n    }\n}\n",
